use notify::{Config, Event, EventKind, RecommendedWatcher, RecursiveMode, Watcher};
use std::path::Path;
use tokio::sync::mpsc;

fn async_watcher<P: AsRef<Path>>(
    path: P,
) -> notify::Result<(RecommendedWatcher, mpsc::Receiver<Result<Event, notify::Error>>)> {
    let (tx, rx) = mpsc::channel(100);

    // Use the raw tx inside the closure; Sender is !Send so we must use blocking_send
    // from within the synchronous watcher callback.
    let mut watcher = RecommendedWatcher::new(
        move |res: Result<Event, notify::Error>| {
            let _ = tx.blocking_send(res);
        },
        Config::default(),
    )?;

    watcher.watch(path.as_ref(), RecursiveMode::Recursive)?;
    Ok((watcher, rx))
}

#[tokio::main]
async fn main() -> notify::Result<()> {
    let path = std::env::args()
        .nth(1)
        .unwrap_or_else(|| ".".into());

    let (_watcher, mut rx) = async_watcher(&path)?;

    println!("Watching {:?} for changes...", path);

    while let Some(res) = rx.recv().await {
        match res {
            Ok(event) if event.kind == EventKind::Any => continue,
            Ok(event) => {
                for path in &event.paths {
                    println!("  {:?} - {:?}", event.kind, path);
                }
            }
            Err(e) => eprintln!("watch error: {:?}", e),
        }
    }

    Ok(())
}
