50 | }
51 |
52 | fn notes_path(dir: &PathBuf) -> PathBuf {
53 |     let expanded = shellexpand::tilde(&dir.to_string_lossy()).to_string();
54 |     let p = PathBuf::from(expanded);
55 |     fs::create_dir_all(&p).ok();
56 |     p.join("notes.json")
57 | }
58 |
59 | fn load_notes(path: &PathBuf) -> Vec<Note> {
60 |     fs::read_to_string(path)
61 |         .ok()
62 |         .and_then(|s| serde_json::from_str(&s).ok())
63 |         .unwrap_or_default()
64 | }
65 |
66 | fn save_notes(path: &PathBuf, notes: &[Note]) {
67 |     let data = serde_json::to_string_pretty(notes).unwrap();
68 |     fs::write(path, data).unwrap();
69 | }
70 |
71 | fn main() {
72 |     let cli = Cli::parse();
73 |     let path = notes_path(&cli.dir);
74 |     let mut notes = load_notes(&path);
75 |
76 |     match cli.command {
77 |         Commands::Add { message, tags } => {
78 |             let id = notes.last().map(|n| n.id + 1).unwrap_or(1);
79 |             let tags = if tags.is_empty() {
80 |                 vec![]
81 |             } else {
82 |                 tags.split(',').map(|t| t.trim().to_string()).collect()
83 |             };
84 |             let note = Note {
85 |                 id,
86 |                 message,
87 |                 tags,
88 |                 created: Local::now().to_rfc3339(),
89 |             };
90 |             notes.push(note);
91 |             save_notes(&path, &notes);
92 |             println!("Note #{} saved.", id);
93 |         }
94 |         Commands::List { tag } => {
95 |             let filtered: Vec<_> = notes
96 |                 .iter()
97 |                 .filter(|n| tag.as_ref().map_or(true, |t| n.tags.contains(t)))
98 |                 .collect();
99 |             if filtered.is_empty() {
100 |                 println!("No notes found.");
101 |                 return;
102 |             }
103 |             for n in &filtered {
104 |                 println!("[{}] {} {:?}", n.id, n.message, n.tags);
105 |             }
106 |         }
107 |         Commands::Rm { id } => {
108 |             let before = notes.len();
109 |             notes.retain(|n| n.id != id);
110 |             if notes.len() == before {
111 |                 eprintln!("Note #{} not found.", id);
112 |                 std::process::exit(1);
113 |             }
114 |             save_notes(&path, &notes);
115 |             println!("Note #{} removed.", id);
116 |         }
117 |     }
118 | }

