use std::any::Any;

/// A message that can be sent to an actor.
/// Uses dynamic dispatch for flexibility — actors downcast to expected types.
pub trait Message: Send + 'static {}

impl Message for String {}
impl Message for i32 {}
impl Message for () {}

/// Envelope wraps a Message in a Box<dyn Any> so the actor system
/// can route it without knowing the concrete type.
pub struct Envelope {
    pub msg: Box<dyn Any + Send>,
}

impl Envelope {
    pub fn new<M: Message>(msg: M) -> Self {
        Self {
            msg: Box::new(msg),
        }
    }

    pub fn extract<M: 'static>(&mut self) -> Option<M> {
        self.msg.downcast_mut::<M>().take()
    }
}
