use crate::message::Envelope;
use async_trait::async_trait;
use std::fmt;

/// Core trait for all actors. Each actor processes messages sequentially.
#[async_trait]
pub trait Actor: Send + Sync + 'static {
    type Msg: Send + 'static;

    async fn receive(&mut self, msg: Self::Msg, ctx: &mut ActorContext<Self::Msg>);

    /// Called before the actor starts processing messages.
    async fn pre_start(&mut self, _ctx: &mut ActorContext<Self::Msg>) {}

    /// Called after the actor stops.
    async fn post_stop(&mut self, _ctx: &mut ActorContext<Self::Msg>) {}
}

/// Context provided to actors during message processing.
/// Allows actors to send messages to other actors and stop themselves.
pub struct ActorContext<M: Send + 'static> {
    pub myself: ActorRef<M>,
    pub system: crate::system::ActorSystem,
}

impl<M: Send + 'static> Clone for ActorContext<M> {
    fn clone(&self) -> Self {
        Self {
            myself: self.myself.clone(),
            system: self.system.clone(),
        }
    }
}

/// A reference to an actor that can be used to send messages.
pub struct ActorRef<M: Send + 'static> {
    tx: tokio::sync::mpsc::Sender<M>,
    path: String,
    started: bool,
}

impl<M: Send + 'static> Clone for ActorRef<M> {
    fn clone(&self) -> Self {
        Self {
            tx: self.tx.clone(),
            path: self.path.clone(),
            started: self.started,
        }
    }
}

impl<M: Send + 'static> ActorRef<M> {
    pub fn new(tx: tokio::sync::mpsc::Sender<M>, path: String) -> Self {
        Self { tx, path, started: false }
    }

    pub async fn tell(&self, msg: M) -> Result<(), ActorError> {
        self.tx.send(msg).await.map_err(|_| ActorError::MailboxClosed)
    }

    pub fn path(&self) -> &str {
        &self.path
    }
}

#[derive(Debug)]
pub enum ActorError {
    MailboxClosed,
    NotFound,
    AlreadyStarted,
}

impl fmt::Display for ActorError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            ActorError::MailboxClosed => write!(f, "mailbox is closed"),
            ActorError::NotFound => write!(f, "actor not found"),
            ActorError::AlreadyStarted => write!(f, "actor already started"),
        }
    }
}

impl std::error::Error for ActorError {}
